+        return Err(format!(
+            "coverage_rows[{row_idx}] field '{field_name}[{path_idx}]' must be repo-relative, got absolute path: {raw_path}"
+        ));
+    }
+
+    let mut parts = Vec::new();
+    for component in candidate.components() {
+        match component {
